parameters.jsCode:
let servicoAtual = $json.servico || [];

// se vier como string (por bug antigo), converte
if (typeof servicoAtual === "string") {
  try {
    servicoAtual = JSON.parse(servicoAtual);
  } catch {
    servicoAtual = [];
  }
}

let novoServico = $json.servicoSelecionado;

if (!Array.isArray(servicoAtual)) {
  servicoAtual = [];
}

if (novoServico && !servicoAtual.includes(novoServico)) {
  servicoAtual.push(novoServico);
}

return {
  json: {
    ...$json,
    servico: servicoAtual
  }
};

const usuarioId = $json.usuario_id;
const servicos = $json.servicos || [];

return servicos.map(servico => ({
  json: {
    usuario_id: usuarioId,
    servico: servico
  }
}));

